const name = $input.item.json.name || 'there';
const business = $input.item.json.business || 'your business';
const email = $input.item.json.email;
const subject = `Welcome! We received your inquiry, ${name}`;
const body = `Hi ${name},\n\nThank you for reaching out! We received your message about ${business} and will be in touch within 24 hours.\n\nBest,\nThe Team`;
return { json: { to: email, subject, body, name, business, timestamp: new Date().toISOString() } };

