const raw = $input.item.json.content?.[0]?.text || '{}';
let parsed = { score: 'warm', reason: 'Unable to parse' };
try { parsed = JSON.parse(raw.match(/\{[^}]+\}/)?.[0] || '{}'); } catch(e) {}
return { json: { ...$input.item.json, score: parsed.score || 'warm', reason: parsed.reason || '' } };

const raw = $input.item.json.content?.[0]?.text || '{}';
let parsed = { category: 'technical', reply: '', needs_human: true };
try { parsed = JSON.parse(raw.match(/\{[\s\S]*\}/)?.[0] || '{}'); } catch(e) {}
return { json: { ...$input.item.json, ...parsed } };

const inv = $input.item.json;
const invoiceNum = 'INV-' + Date.now().toString().slice(-6);
const dueDate = new Date(Date.now() + 14 * 86400000).toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' });
const body = `Dear ${inv.client_name},

Please find your invoice below.

Invoice: ${invoiceNum}
Project: ${inv.project_name}
Amount: $${inv.amount}
Due: ${dueDate}

Payment instructions: [YOUR PAYMENT LINK]

Thank you for your business!
The Team`;
return { json: { ...inv, invoiceNum, dueDate, emailBody: body } };
